secrets = [b"test", b"testing", b"secret", b"secret-key", b"dev", b"development", b"changeme", b"password", b"supersecretkey", b"supersecret", b"trading", b"trading-platform", b"flask", b"debug", b"production", b"prod", b"admin", b"key", b"mysecretkey"]

candidates = []
for salt in salts:
    for secret in secrets:
        dk = hmac.new(secret, salt, hashlib.sha1).digest()
        for value in [data, data+b"."+ts, ts+b"."+data]:
            s = b64url(hmac.new(dk, value, hashlib.sha1).digest())
            if s == sig:
                candidates.append((secret.decode(errors='ignore'), salt.decode(errors='ignore'), value.decode()))

print("matches:", candidates)
